#!/usr/bin/env bash
# tools/gen/generate_pav.sh — pav parity row for both archives.
#
# Plots referenced by tryit.jsx's PLOT group, "pav · short-flag plotter":
#   plots/pav/<ar>/profile__jdft.png
#   plots/pav/<ar>/dynamic__jd.png   (already generated by generate_plots.sh)
#   plots/pav/<ar>/stack__jd.png
#   plots/pav/<ar>/stokes__jdft.png

source "$(dirname "${BASH_SOURCE[0]}")/_common.sh"

for ar in J0437-4715 J1909-3744; do
    src="${SRC[$ar]:-}"
    [[ -f "$src" ]] || { log_skip "no archive for $ar" "$src"; continue; }
    out="$OUT/pav/$ar"
    mkdir -p "$out"

    declare -A FLAGS=(
        [profile]="-SFTp -j D"
        [dynamic]="-DFTp -j D"
        [stack]="-GTp -j D"
        [stokes]="-SFTpd -j D"
    )
    declare -A SUFFIX=(
        [profile]="jdft" [dynamic]="jd" [stack]="jd" [stokes]="jdft"
    )

    for view in profile dynamic stack stokes; do
        f="$out/${view}__${SUFFIX[$view]}.png"
        run "pav $view ($ar)" -- pav ${FLAGS[$view]} "$src" -g "$f"/PNG || continue
        append_manifest "pav/$ar/${view}__${SUFFIX[$view]}.png" "$ar" \
            "$(basename "$src")" \
            "pav ${FLAGS[$view]} <src> -g <out>/PNG"
    done
done
